module.render:
const color = args.color || 'var(--accent-color)';
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const hl = parseInt(args.highlight, 10) || 0;
const align = ({ left: 'left', center: 'center', right: 'right' })[String(args.align || 'center').toLowerCase()] || 'center';
const markColor = args.markcolor || '#16a34a';
const zebra = String(args.zebra) === 'true';
const rows = sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).map((l) => l.split('|').map((c) => c.trim()));
if (!rows.length) return `<div>(comparetable: header row then feature rows, cells split by | )</div>`;
const cellHtml = (c, ci) => {
  const v = c.toLowerCase();
  const hcls = (ci >= 1 && ci === hl) ? ' mdp-ct-hl' : '';
  if (['yes','y','true','✓','o','○'].includes(v)) return `<td class="mdp-ct-yes${hcls}">✓</td>`;
  if (['no','n','false','✗','x','×','-','—'].includes(v)) return `<td class="mdp-ct-no${hcls}">✗</td>`;
  return `<td class="${hcls.trim()}">${esc(c)}</td>`;
};
const tcls = 'mdp-mod-comparetable' + (zebra ? ' mdp-ct-zebra' : '');
let html = `\n\n<table class="${tcls}" style="--ct-color:${color}; --ct-align:${align}; --ct-yes:${markColor};"><thead><tr>`;
rows[0].forEach((c, ci) => { html += `<th class="${ci >= 1 && ci === hl ? 'mdp-ct-hl' : ''}">${esc(c)}</th>`; });
html += `</tr></thead><tbody>`;
rows.slice(1).forEach((r) => { html += `<tr><th scope="row">${esc(r[0] || '')}</th>` + r.slice(1).map((c, i) => cellHtml(c, i + 1)).join('') + `</tr>`; });
html += `</tbody></table>\n\n`;
return html;
